qry:select.qry:xquery:
			for $r in sql('
	SELECT 
		count(t0.oi_carpeta) as cant1
		{%?(#PARAM:@rol='USER')
		 {% ,\'./ROLE/LEGALES_USER\' as POLICY  %}
			{% %}
		%}


	FROM 
		LEG01_CARPETAS as t0
		{%?(#PARAM:@oi_rol_parte!='' OR #PARAM:@oi_sujeto_parte!='')
			{% , LEG01_PARTES as t1 %}
			{% %}
		%} 
		{%?(#PARAM:@oi_grupo_jur!='' OR #PARAM:@oi_jurisdiccion!='')
		{% ,LEG01_RADICACION as R
			 ,LEG48_JURISDICCION as J

		JOIN
		R.oi_carpeta INNER t0.oi_carpeta,
		R.oi_jurisdiccion INNER J.oi_jurisdiccion
		%}
		{% %}
		%}
	WHERE
	1=1 		 


	{%?(#PARAM:@oi_empresa!='') {% AND t0.oi_empresa = {#PARAM:@oi_empresa} %} {% %} %}
	{%?(#PARAM:@nrosWhere!='') {% AND ({%=#PARAM:@nrosWhere%}) %} {% %} %}
	{%?(#PARAM:@codsWhere!='') {% AND ({%=#PARAM:@codsWhere%}) %} {% %} %}{%?(#PARAM:@d_carpeta!='') {% AND CONTAIN(t0.d_carpeta, \'{%=#PARAM:@d_carpeta%}\') %} {% %} %}
	{%?(#PARAM:@f_carpeta_d!='') {% AND t0.f_carpeta >= {#PARAM:@f_carpeta_d} %} {% %} %}
	{%?(#PARAM:@f_carpeta_h!='') {% AND t0.f_carpeta <  {Datetime(Number(Datetime(#PARAM:@f_carpeta_h))+1)} %} {% %} %}
	{%?(#PARAM:@oi_estado_carpeta!='') {% AND t0.oi_estado_carpeta = {#PARAM:@oi_estado_carpeta} %} {% %} %}
	{%?(#PARAM:@oi_ubicacion!='') {% AND t0.oi_ubicacion = {#PARAM:@oi_ubicacion} %} {% %} %}
	{%?(#PARAM:@oi_sujeto!='') {% AND t0.oi_sujeto = {#PARAM:@oi_sujeto} %} {% %} %}
	{%?(#PARAM:@oi_rol_parte!='' OR #PARAM:@oi_sujeto_parte!='')	{% AND t0.oi_carpeta = t1.oi_carpeta %} {% %} %}
	{%?(#PARAM:@oi_rol_parte!='')	{% AND t1.oi_rol = {#PARAM:@oi_rol_parte} %} {% %} %}
	{%?(#PARAM:@oi_sujeto_parte!='')	{% AND t1.oi_sujeto = {#PARAM:@oi_sujeto_parte} %} {% %} %}
	{%?(#PARAM:@oi_grupo_jur!='')	{% AND J.oi_grupo_jur = {#PARAM:@oi_grupo_jur} %} {% %} %}			
	{%?(#PARAM:@oi_jurisdiccion!='')	{% AND J.oi_jurisdiccion = {#PARAM:@oi_jurisdiccion} %} {% %} %}
	{%?(#PARAM:@c_opcion!='') {% AND CONTAIN(t0.d_custom_1, \'{%=#PARAM:@c_opcion%}\') %} {% %} %}																																																	                                                			
	{%?(#PARAM:@cerrado='2')	{% AND t0.l_cerrado = 1 %} {% %} %}
	{%?(#PARAM:@cerrado='3')	{% AND t0.l_cerrado = 0 %} {% %} %}	
	{%? (#PARAM:@TIPOSCARPETAS_IDs!='') {% AND t0.oi_tipo_carpeta {%=#PARAM:@TIPOSCARPETAS_IDs%} %} {%  %} %}
	{%?(#PARAM:@rol='USER')
		 {% 

		  AND t0.oi_ubicacion IN (SELECT LEG58_SEGURIDAD.oi_ubicacion 

	 												FROM LEG58_SEGURIDAD
	  											WHERE LEG58_SEGURIDAD.oi_usuario_sys = \'{%=$proxy/@ETTY%}\')					  
		  %}
			{% %}
		%}		

')/ROWS/ROW

		for $r in sql('
MAXSIZE 300
SELECT 
	  t0.oi_carpeta as oi_carpeta
	{%?(#PARAM:@rol='USER')
	 {% ,\'./ROLE/LEGALES_USER\' as POLICY  %}
		{% %}
	%}

FROM 
	LEG01_CARPETAS as t0
	{%?(#PARAM:@oi_rol_parte!='' OR #PARAM:@oi_sujeto_parte!='')
		{% , LEG01_PARTES as t1 %}
		{% %}
	%}
	{%?(#PARAM:@oi_grupo_jur!='' OR #PARAM:@oi_jurisdiccion!='')
	{% ,LEG01_RADICACION as R
		 ,LEG48_JURISDICCION as J

	JOIN
	R.oi_carpeta INNER t0.oi_carpeta,
	R.oi_jurisdiccion INNER J.oi_jurisdiccion
	%}
	{% %}
	%}
WHERE
1=1


{%?(#PARAM:@oi_empresa!='') {% AND t0.oi_empresa = {#PARAM:@oi_empresa} %} {% %} %}
{%?(#PARAM:@nrosWhere!='') {% AND ({%=#PARAM:@nrosWhere%}) %} {% %} %}
{%?(#PARAM:@codsWhere!='') {% AND ({%=#PARAM:@codsWhere%}) %} {% %} %}
{%?(#PARAM:@d_carpeta!='') {% AND CONTAIN(t0.d_carpeta, \'{%=#PARAM:@d_carpeta%}\') %} {% %} %}
{%?(#PARAM:@f_carpeta_d!='') {% AND t0.f_carpeta >= {#PARAM:@f_carpeta_d} %} {% %} %}
{%?(#PARAM:@f_carpeta_h!='') {% AND t0.f_carpeta <  {Datetime(Number(Datetime(#PARAM:@f_carpeta_h))+1)} %} {% %} %}
{%?(#PARAM:@oi_estado_carpeta!='') {% AND t0.oi_estado_carpeta = {#PARAM:@oi_estado_carpeta} %} {% %} %}
{%?(#PARAM:@oi_ubicacion!='') {% AND t0.oi_ubicacion = {#PARAM:@oi_ubicacion} %} {% %} %}
{%?(#PARAM:@oi_sujeto!='') {% AND t0.oi_sujeto = {#PARAM:@oi_sujeto} %} {% %} %}
{%?(#PARAM:@oi_rol_parte!='' OR #PARAM:@oi_sujeto_parte!='')	{% AND t0.oi_carpeta = t1.oi_carpeta %} {% %} %}
{%?(#PARAM:@oi_rol_parte!='')	{% AND t1.oi_rol = {#PARAM:@oi_rol_parte} %} {% %} %}
{%?(#PARAM:@oi_sujeto_parte!='')	{% AND t1.oi_sujeto = {#PARAM:@oi_sujeto_parte} %} {% %} %}
{%?(#PARAM:@oi_grupo_jur!='')	{% AND J.oi_grupo_jur = {#PARAM:@oi_grupo_jur} %} {% %} %}						
{%?(#PARAM:@oi_jurisdiccion!='')	{% AND J.oi_jurisdiccion = {#PARAM:@oi_jurisdiccion} %} {% %} %}						
{%?(#PARAM:@c_opcion!='') {% AND CONTAIN(t0.d_custom_1, \'{%=#PARAM:@c_opcion%}\') %} {% %} %}																																																	                                                			
{%?(#PARAM:@l_cerrado='1')	{% AND t0.l_cerrado = 0 %} {% %} %}												
{%?(#PARAM:@cerrado='2')	{% AND t0.l_cerrado = 1 %} {% %} %}
{%?(#PARAM:@cerrado='3')	{% AND t0.l_cerrado = 0 %} {% %} %}
{%?(#PARAM:@rol='USER')
	 {% 

	  AND t0.oi_ubicacion IN (SELECT LEG58_SEGURIDAD.oi_ubicacion 

 												FROM LEG58_SEGURIDAD
  											WHERE LEG58_SEGURIDAD.oi_usuario_sys = \'{%=$proxy/@ETTY%}\')					  
	  %} 

		{% %}
	%}
{% %}
{%?(#PARAM:@listDocs!='' OR #PARAM:@listlegajos!='')
{%
	AND t0.oi_carpeta IN (
			SELECT LEG01_PARTES.oi_carpeta
			FROM 
			VW_LEG_SUJETOS_ACTOR,
			LEG01_PARTES 
			WHERE 
			   LEG01_PARTES.oi_sujeto = VW_LEG_SUJETOS_ACTOR.oi_sujeto   
			AND (
			 	  CONTAIN(VW_LEG_SUJETOS_ACTOR.C_NRO_DOCUMENTO,\'{%=$PARAM/@listDocs%}\') 
			OR  
				CONTAIN(VW_LEG_SUJETOS_ACTOR.C_LEGAJO,\'{%=$PARAM/@listlegajos%}\') 

			))

%} 
{% %}
%}	  
{%? (#PARAM:@TIPOSCARPETAS_IDs!='') {% AND t0.oi_tipo_carpeta {%=#PARAM:@TIPOSCARPETAS_IDs%} %} {%  %} %} 			

ORDER BY oi_carpeta asc')/ROWS/ROW
